import React from 'react';
import { NodeProps } from 'react-flow-renderer';

const COLORS: Record<string, string> = {
  aws: '#ff9900',
  gcp: '#4285f4',
  azure: '#007FFF',
  compute: '#00c853',
  network: '#ffab00',
  storage: '#b388ff',
};

export default function CustomNode({ data }: NodeProps) {
  const { label, subtype } = data as { label: string; subtype?: string };
  const background = subtype ? COLORS[subtype] || '#eee' : '#eee';

  return (
    <div
      style={{
        padding: 10,
        border: '1px solid #222',
        borderRadius: 3,
        backgroundColor: background,
        color: '#fff',
        fontWeight: 'bold',
        textAlign: 'center',
        minWidth: 100,
      }}
    >
      {label}
    </div>
  );
}
